unächst, after setting up the library, you can import its Radio, RadioGroup, and RadioControl components. Here’s an example of how to import and use RadioGroup:

```jsx
import RadioGroup from'react-access-radio';
import { render } from'react-proxy-hot';

function MyForm() {
  return (
    <RadioGroup>
      <RadioGroup
        onGenerate={(groupProps, formValues, formState) => (
          <div key={groupProps.id}>
            <groupProps.label>Choose an option:</groupProps.label>
            <RadioProps
              {...groupProps.fields.map((radio, { name }) => (
                <div key={radio.id}>
                  <label>{radio.label}</label>
                  <input
                    name={name}
                    value={radio.value}
                    hidden={!radio.hidden}
                  />
                </div>
              ))}
            </RadioProps>
          ))}
        </RadioGroup>
      </RadioGroup>
    </RadioGroup>
  );
}
export default MyForm
